begin;
create table public.history_import_sessions(id uuid primary key,domain_id text not null,workspace_id uuid not null references public.workspaces(id),executive_identity_id uuid not null references public.executive_identities(id),source_type text not null,status text not null,stage text not null,source_filename text,consented_at timestamptz not null,retention_choice text not null check(retention_choice in('Discard after extraction','Retain reference')),import_version text not null,summary jsonb not null default '{}',created_at timestamptz not null default now(),completed_at timestamptz,created_by uuid not null references public.executive_identities(id),unique(workspace_id,domain_id),unique(workspace_id,id));
create table public.professional_experiences(id uuid primary key,domain_id text not null,workspace_id uuid not null references public.workspaces(id),executive_identity_id uuid not null references public.executive_identities(id),import_session_id uuid not null,organization_name text not null,role_title text not null,start_date date,end_date date,is_current boolean not null default false,employment_type text not null,confidence text not null,notes text,provenance jsonb not null,created_at timestamptz not null default now(),created_by uuid not null references public.executive_identities(id),version integer not null default 1,archived_at timestamptz,unique(workspace_id,domain_id),unique(workspace_id,id),foreign key(workspace_id,import_session_id) references public.history_import_sessions(workspace_id,id),check(end_date is null or start_date is null or end_date>=start_date));
create table public.history_achievements(id uuid primary key,domain_id text not null,workspace_id uuid not null references public.workspaces(id),executive_identity_id uuid not null references public.executive_identities(id),import_session_id uuid not null,experience_id uuid not null,achievement_text text not null,provenance jsonb not null,created_at timestamptz not null default now(),created_by uuid not null references public.executive_identities(id),unique(workspace_id,domain_id),foreign key(workspace_id,import_session_id) references public.history_import_sessions(workspace_id,id),foreign key(workspace_id,experience_id) references public.professional_experiences(workspace_id,id));
create table public.history_education(id uuid primary key,domain_id text not null,workspace_id uuid not null references public.workspaces(id),executive_identity_id uuid not null references public.executive_identities(id),import_session_id uuid not null,institution text not null,qualification text,start_date date,end_date date,confidence text not null,provenance jsonb not null,created_at timestamptz not null default now(),created_by uuid not null references public.executive_identities(id),unique(workspace_id,domain_id),foreign key(workspace_id,import_session_id) references public.history_import_sessions(workspace_id,id),check(end_date is null or start_date is null or end_date>=start_date));
create table public.history_certifications(id uuid primary key,domain_id text not null,workspace_id uuid not null references public.workspaces(id),executive_identity_id uuid not null references public.executive_identities(id),import_session_id uuid not null,name text not null,issuer text,issued_at date,confidence text not null,provenance jsonb not null,created_at timestamptz not null default now(),created_by uuid not null references public.executive_identities(id),unique(workspace_id,domain_id),foreign key(workspace_id,import_session_id) references public.history_import_sessions(workspace_id,id));
create table public.history_board_roles(id uuid primary key,domain_id text not null,workspace_id uuid not null references public.workspaces(id),executive_identity_id uuid not null references public.executive_identities(id),import_session_id uuid not null,organization_name text not null,role_title text not null,role_kind text not null check(role_kind in('Board','Advisory')),start_date date,end_date date,confidence text not null,provenance jsonb not null,created_at timestamptz not null default now(),created_by uuid not null references public.executive_identities(id),unique(workspace_id,domain_id),foreign key(workspace_id,import_session_id) references public.history_import_sessions(workspace_id,id));
create table public.history_import_records(id uuid primary key,workspace_id uuid not null references public.workspaces(id),import_session_id uuid not null,record_kind text not null,record_domain_id text not null,decision text not null,confidence text not null,evidence jsonb not null default '[]',created_at timestamptz not null default now(),created_by uuid not null references public.executive_identities(id),foreign key(workspace_id,import_session_id) references public.history_import_sessions(workspace_id,id));
create table public.history_import_decisions(id uuid primary key,workspace_id uuid not null references public.workspaces(id),import_session_id uuid not null,import_record_id uuid not null references public.history_import_records(id),decision text not null,reason text,decided_at timestamptz not null default now(),created_by uuid not null references public.executive_identities(id),foreign key(workspace_id,import_session_id) references public.history_import_sessions(workspace_id,id));
create table public.history_import_conflicts(id uuid primary key,workspace_id uuid not null references public.workspaces(id),import_session_id uuid not null,conflict_type text not null,title text not null,explanation text not null,suggested_action text not null,severity text not null,status text not null default 'Open',record_ids jsonb not null default '[]',created_at timestamptz not null default now(),created_by uuid not null references public.executive_identities(id),foreign key(workspace_id,import_session_id) references public.history_import_sessions(workspace_id,id));
create table public.history_import_audit_events(id uuid primary key,workspace_id uuid not null references public.workspaces(id),import_session_id uuid not null,event_type text not null,safe_metadata jsonb not null default '{}',occurred_at timestamptz not null default now(),created_by uuid not null references public.executive_identities(id),foreign key(workspace_id,import_session_id) references public.history_import_sessions(workspace_id,id));
do $$declare t text;begin foreach t in array array['history_import_sessions','professional_experiences','history_achievements','history_education','history_certifications','history_board_roles','history_import_records','history_import_decisions','history_import_conflicts','history_import_audit_events'] loop execute format('alter table public.%I enable row level security',t);execute format('create policy %I on public.%I for select to authenticated using(public.is_active_workspace_member(workspace_id))',t||'_read',t);execute format('create policy %I on public.%I for insert to authenticated with check(public.is_active_workspace_member(workspace_id))',t||'_insert',t);end loop;end$$;
do $$declare t text;begin foreach t in array array['history_import_sessions','professional_experiences','history_achievements','history_education','history_certifications','history_board_roles','history_import_records','history_import_decisions','history_import_conflicts'] loop execute format('create policy %I on public.%I for update to authenticated using(public.is_active_workspace_member(workspace_id)) with check(public.is_active_workspace_member(workspace_id))',t||'_update',t);end loop;end$$;
grant select,insert,update on public.history_import_sessions,public.professional_experiences,public.history_achievements,public.history_education,public.history_certifications,public.history_board_roles,public.history_import_records,public.history_import_decisions,public.history_import_conflicts to authenticated;grant select,insert on public.history_import_audit_events to authenticated;revoke all on all tables in schema public from anon;revoke delete on all tables in schema public from authenticated;
create index history_import_sessions_workspace_created_idx on public.history_import_sessions(workspace_id,created_at desc);create index professional_experiences_workspace_dates_idx on public.professional_experiences(workspace_id,start_date desc,end_date desc);create index professional_experiences_workspace_org_idx on public.professional_experiences(workspace_id,organization_name);create index history_import_records_session_idx on public.history_import_records(workspace_id,import_session_id);create index history_import_conflicts_session_idx on public.history_import_conflicts(workspace_id,import_session_id,status);create index history_import_audit_session_idx on public.history_import_audit_events(workspace_id,import_session_id,occurred_at);
commit;
